import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [showDecrypted, setShowDecrypted] = useState(false);
    const navigate = useNavigate();

    const role = localStorage.getItem("role");

    const fetchLeads = async (decrypted = false) => {
        const token = localStorage.getItem("token");
        if (!token) {
            navigate("/");
            return;
        }

        try {
            const res = await axios.get("http://localhost:8000/leads", {
                headers: { Authorization: `Bearer ${token}` },
                params: { decrypted: decrypted ? 1 : 0 },
            });
            setLeads(res.data || []);
        } catch (err) {
            console.error("Error fetching leads:", err);
            if (err.response && err.response.status === 401) {
                setError("Session expired. Please log in again.");
                localStorage.removeItem("token");
                localStorage.removeItem("role");
                navigate("/");
            } else {
                setError("Failed to load leads. Please try again later.");
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLeads(showDecrypted);
    }, [navigate, showDecrypted]);

    return (
        <div className="container mt-4">
            <div className="card shadow-lg border-0 rounded-3">
                <div className="card-header d-flex justify-content-between align-items-center bg-primary text-white">
                    <h4 className="mb-0">📋 Leads</h4>

                    {(role === "admin" || role === "agent") && (
                        <button
                            className="btn btn-light btn-sm shadow-sm"
                            onClick={() => setShowDecrypted((prev) => !prev)}
                        >
                            {showDecrypted ? "🔒 Show Encrypted" : "🔑 Show Decrypted"}
                        </button>
                    )}
                </div>

                <div className="card-body">
                    {loading ? (
                        <div className="text-center py-4">
                            <div className="spinner-border text-primary" role="status"></div>
                            <p className="mt-2">Loading leads...</p>
                        </div>
                    ) : error ? (
                        <div className="alert alert-danger">{error}</div>
                    ) : leads.length > 0 ? (
                        <div className="table-responsive">
                            <table className="table table-hover align-middle">
                                <thead className="table-dark">
                                    <tr>
                                        <th>Name</th>
                                        <th>Username</th>
                                        <th>Email</th>
                                        <th>Phone</th>
                                        <th>Company URL</th>
                                        <th>Company Name</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {leads.map((lead) => (
                                        <tr key={lead.id}>
                                            <td>{lead.name || "-"}</td>
                                            <td>{lead.username || "-"}</td>
                                            <td>{lead.email || "-"}</td>
                                            <td>{lead.phone || "-"}</td>
                                            <td>
                                                {lead.link_url ? (
                                                    <a
                                                        href={lead.link_url}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="text-decoration-none"
                                                    >
                                                        🌐 Visit
                                                    </a>
                                                ) : "-"}
                                            </td>
                                            <td>{lead.company_name || "-"}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    ) : (
                        <p className="text-muted text-center">No leads found.</p>
                    )}
                </div>
            </div>
        </div>
    );
}

export default Leads;
